def solve(width, height, target_width, target_height):
    if width <= 0 or height <= 0 or target_width <= 0 or target_height <= 0:
        return "Invalid dimensions"

    aspect_ratio_input = width / height
    aspect_ratio_target = target_width / target_height

    if aspect_ratio_input == aspect_ratio_target:
        return "Dimensions match"
    elif aspect_ratio_input > aspect_ratio_target:
        return "Input is wider than target"
    else:
        return "Input is taller than target"
